let allData = {{workflowparams:allData}}
const updatedSM = []
const saveAs = {{workflowparams:saveAs}}

if (saveAs === "Cancelled") {
  const rawData = {{node:get_node_czmdH3Jw.data.data}}
  allData = Array.isArray(rawData) ? rawData[0] : rawData
}

const normalizeCategory = (cat) => {
  if (cat === "UNR") return "Unrestricted"
  if (cat === "BLK") return "Blocked"
  return cat
}

for (const [index, smLineItem] of allData.stock_movement.entries()) {
  smLineItem.organization_id = allData.organization_id;
  smLineItem.issuing_plant = allData.issuing_operation_faci || null;
  smLineItem.receiving_plant = allData.receiving_operation_faci || null;
  smLineItem.line_index = index + 1;

  smLineItem.category = normalizeCategory(smLineItem.category)

  if (smLineItem.temp_qty_data) {
    try {
      const parsed = JSON.parse(smLineItem.temp_qty_data)
      if (Array.isArray(parsed)) {
        for (const row of parsed) {
          row.category = normalizeCategory(row.category)
        }
        smLineItem.temp_qty_data = JSON.stringify(parsed)
      }
    } catch (e) {
      // leave as-is if not valid JSON
    }
  }

  updatedSM.push(smLineItem)
}

allData.stock_movement = updatedSM

if ({{workflowparams:pageStatus}} === "Add") {
  allData.stock_movement_status = "Draft"
}

if (saveAs === "Draft") {
  if(allData.stock_movement_no_type !== -9999 && (
  !allData.stock_movement_no || allData.stock_movement_no === null || allData.stock_movement_no === ''
)) {
  allData.stock_movement_no = 'draft'
  }
} else {
  if (
  allData.stock_movement_no_type !== -9999 &&
  (!allData.stock_movement_no ||
    allData.stock_movement_no === null ||
    allData.stock_movement_no === "" ||
    allData.stock_movement_status !== "In Progress")
) {
  allData.stock_movement_no = 'issued'
  }
}

return {
  allData: allData,
  stock_movement_status: allData.stock_movement_status,
  is_production_order: allData.is_production_order
}

return {
  required_fields: JSON.stringify([
  { name: "stock_movement_no", label: "Stock Movement No" },
  { name: "movement_type", label: "Movement Type" },
  { name: "issue_date", label: "Issue Date" },
  { name: "issuing_operation_faci", label: "Issuing Operation Facility" },
  {
    name: "stock_movement",
    label: "Item Information",
    isArray: true,
    arrayType: "object",
    arrayFields: [],
  },
]),
  data: JSON.stringify({
    stock_movement_no: {{node:code_node_yPlLXIZW.data.allData.stock_movement_no}},
    movement_type: {{node:code_node_yPlLXIZW.data.allData.movement_type}},
    issue_date: {{node:code_node_yPlLXIZW.data.allData.issue_date}},
    issuing_operation_faci: {{node:code_node_yPlLXIZW.data.allData.issuing_operation_faci}},
    stock_movement: {{node:code_node_yPlLXIZW.data.allData.stock_movement}}
  })
}

const allData = {{node:code_node_yPlLXIZW.data.allData}}
const subformData = allData.stock_movement || []

let locationFailed = 0;
let quantityFailed = 0
let locationMessage
let quantityMessage

const hasValidBalance = (tempData) => {
  if (!tempData) return false;
  try {
    const parsed = JSON.parse(tempData);
    return Array.isArray(parsed) && parsed.some(
      (entry) => entry.sm_quantity && parseFloat(entry.sm_quantity) > 0
    );
  } catch (e) {
    return false;
  }
};

for (let i = 0; i < subformData.length; i++) {
  const item = subformData[i];
  // Skip empty lines (no quantity selected) so they don't false-fail location validation
  if (!hasValidBalance(item.temp_qty_data)) continue;
  if (!item.location_id) {
    locationFailed = 1;
    locationMessage = `Location ID is required for item ${i + 1} in Location Transfer`
    break;
  }
}

const hasQuantity = subformData.some((line) => hasValidBalance(line.temp_qty_data));

if (!hasQuantity) {
  quantityFailed = 1
  quantityMessage = 'No quantity selected to transfer'
}

return {
  locationFailed: locationFailed,
  quantityFailed: quantityFailed,
  locationMessage: locationMessage,
  quantityMessage: quantityMessage
};

const roundQty = (v) => parseFloat(parseFloat(v || 0).toFixed(3));
const qtyStr = (v) => Math.max(0, roundQty(v)).toFixed(3);

const allData = {{node:code_node_yPlLXIZW.data.allData}};
const openRaw = {{node:search_node_LOTitOpenCancel.data.data}};
const openRows = Array.isArray(openRaw) ? openRaw : (openRaw ? [openRaw] : []);

const lines = allData.stock_movement || [];
const movements = [];
const materialSet = {};

// Cancel reverses the In-Progress staged state: subtract In Transit at the
// destination bin (relocated; was source), add the ORIGINAL category back at the
// source bin (fix: the old workflow hardcoded "Unrestricted").
for (const line of lines) {
  const D = line.location_id;
  let entries = [];
  try { entries = JSON.parse(line.temp_qty_data || "[]"); } catch (e) { entries = []; }
  if (!Array.isArray(entries)) entries = [];
  for (const e of entries) {
    const qty = roundQty(e.sm_quantity);
    if (qty <= 0) continue;
    const mat = e.material_id || line.item_selection;
    materialSet[mat] = true;
    movements.push({
      material_id: mat,
      batch_id: e.batch_id || null,
      quantity: qty,
      material_uom: e.material_uom || line.quantity_uom,
      subtractCategory: "In Transit",
      subtractLocation: D,
      addCategory: e.category || "Unrestricted",
      addLocation: e.location_id,
      handling_unit_id: e.handling_unit_id || null,
      manufacturing_date: e.manufacturing_date || null,
      expired_date: e.expired_date || null,
    });
  }
}

const transitUpdates = [];
for (const r of openRows) {
  if (r.status !== "In Transit") continue;
  transitUpdates.push({ id: r.id, open_qty: qtyStr(0), status: "Cancelled" });
}

return {
  movements,
  movementsLength: movements.length,
  transitUpdates,
  hasTransitUpdates: transitUpdates.length > 0 ? 1 : 0,
  materialIds: Object.keys(materialSet),
  plant_id: allData.issuing_operation_faci,
  organization_id: allData.organization_id,
  stock_movement_no: allData.stock_movement_no,
  doc_date: allData.issue_date,
};

const movements = {{node:code_node_LOTcancelCompute.data.movements}} || [];
const idxRaw = {{node:get_cache_node_LOTcancelIdx.data}};
const index = idxRaw ? parseInt(idxRaw, 10) : 0;
const m = movements[index] || {};

const itemsRaw = {{node:search_node_LOTitItemsCancel.data.data}} || [];
const items = Array.isArray(itemsRaw) ? itemsRaw : [itemsRaw];
const itemData = items.find((i) => i && String(i.id) === String(m.material_id)) || null;

return {
  material_id: m.material_id,
  batch_id: m.batch_id || null,
  quantity: m.quantity,
  material_uom: m.material_uom,
  subtractCategory: m.subtractCategory,
  subtractLocation: m.subtractLocation,
  addCategory: m.addCategory,
  addLocation: m.addLocation,
  handling_unit_id: m.handling_unit_id || null,
  manufacturing_date: m.manufacturing_date || null,
  expired_date: m.expired_date || null,
  itemData: itemData,
  index: index,
  nextIndex: index + 1,
};

const roundQty = (v) => parseFloat(parseFloat(v || 0).toFixed(3));
const allData = {{node:code_node_yPlLXIZW.data.allData}};
const lines = allData.stock_movement || [];

// Source-availability guard on the Draft departure. Aggregate demand per unique
// (material, source bin, batch, category, uom) across ALL lines, then check each
// once with the SUMMED qty. This closes the stateless-per-line hole where two
// lines drawing the same source balance each passed a check the sum would fail.
const map = {};
for (const line of lines) {
  let entries = [];
  try { entries = JSON.parse(line.temp_qty_data || "[]"); } catch (e) { entries = []; }
  if (!Array.isArray(entries)) entries = [];
  for (const e of entries) {
    const qty = roundQty(e.sm_quantity);
    if (qty <= 0) continue;
    const mat = e.material_id || line.item_selection;
    const uom = e.material_uom || line.quantity_uom;
    const cat = e.category || "Unrestricted";
    const key = mat + "|" + e.location_id + "|" + (e.batch_id || "") + "|" + cat + "|" + uom;
    if (map[key]) map[key].quantity = roundQty(map[key].quantity + qty);
    else map[key] = {
      material_id: mat, location_id: e.location_id, batch_id: e.batch_id || null,
      category: cat, material_uom: uom, quantity: qty,
    };
  }
}

const aggregated = Object.values(map);
return {
  aggregated,
  aggLength: aggregated.length,
  plant_id: allData.issuing_operation_faci,
  organization_id: allData.organization_id,
};

const aggregated = {{node:code_node_LOTprecheckAgg.data.aggregated}} || [];
const idxRaw = {{node:get_cache_node_LOTprecheckIdx.data}};
const index = idxRaw ? parseInt(idxRaw, 10) : 0;
const b = aggregated[index] || {};
return {
  material_id: b.material_id,
  location_id: b.location_id,
  batch_id: b.batch_id || null,
  category: b.category,
  material_uom: b.material_uom,
  quantity: b.quantity,
  index: index,
  nextIndex: index + 1,
};

const subFormData = {{node:code_node_yPlLXIZW.data.allData.stock_movement}}

let isNotEqual = 0;

for (const sm of subformData) {
  if (sm.total_quantity !== sm.requested_qty) {
    isNotEqual = 1;
    break;
  }
}

return {
  isNotEqual: isNotEqual,
};

const roundQty = (v) => parseFloat(parseFloat(v || 0).toFixed(3));
const qtyStr = (v) => Math.max(0, roundQty(v)).toFixed(3);

const currentData = {{node:code_node_yPlLXIZW.data.allData}};
const initialData = {{node:get_node_Ij7YbXCA.data.data}} || {};
const openRaw = {{node:search_node_LOTitOpenRecon.data.data}};
const openRows = Array.isArray(openRaw) ? openRaw : (openRaw ? [openRaw] : []);

const ctx = {
  docId: currentData.id || "",
  docNo: currentData.stock_movement_no || "",
  plantId: currentData.issuing_operation_faci,
  orgId: currentData.organization_id,
  docDate: currentData.issue_date,
};

const lineStaging = (line) => {
  const D = line.location_id;
  let entries = [];
  try { entries = JSON.parse(line.temp_qty_data || "[]"); } catch (e) { entries = []; }
  if (!Array.isArray(entries)) entries = [];
  const byKey = {};
  for (const e of entries) {
    const qty = roundQty(e.sm_quantity); if (qty <= 0) continue;
    const mat = e.material_id || line.item_selection;
    const k = `${mat}|${e.location_id}|${e.batch_id || ""}|${e.category || "Unrestricted"}`;
    if (byKey[k]) byKey[k].qty = roundQty(byKey[k].qty + qty);
    else byKey[k] = { material_id: mat, source: e.location_id, batch_id: e.batch_id || null,
      category: e.category || "Unrestricted", qty, material_uom: e.material_uom || line.quantity_uom,
      handling_unit_id: e.handling_unit_id || null, manufacturing_date: e.manufacturing_date || null,
      expired_date: e.expired_date || null };
  }
  return { D, byKey };
};

const initLines = {}; for (const l of (initialData.stock_movement || [])) if (l.id) initLines[l.id] = l;
const curLines = {}; for (const l of (currentData.stock_movement || [])) if (l.id) curLines[l.id] = l;
const allIds = Object.keys(initLines).concat(Object.keys(curLines).filter(x => !initLines[x]));

const movements = [];
const materialSet = {};
const transitDelta = new Map();
const bumpTransit = (mat, batch, bin, delta, meta) => {
  const k = `${mat}|${batch || ""}|${bin}`;
  const cur = transitDelta.get(k);
  if (cur) cur.delta = roundQty(cur.delta + delta);
  else transitDelta.set(k, { delta: roundQty(delta), material: mat, batch: batch || null, bin, meta });
};
const pushPair = (base, subCat, subLoc, addCat, addLoc, qty) => {
  if (qty <= 0) return;
  materialSet[base.material_id] = true;
  movements.push({ material_id: base.material_id, batch_id: base.batch_id, quantity: roundQty(qty),
    material_uom: base.material_uom, handling_unit_id: base.handling_unit_id,
    manufacturing_date: base.manufacturing_date, expired_date: base.expired_date,
    subtractCategory: subCat, subtractLocation: subLoc, addCategory: addCat, addLocation: addLoc });
};

for (const id of allIds) {
  const init = initLines[id] ? lineStaging(initLines[id]) : null;
  const cur = curLines[id] ? lineStaging(curLines[id]) : null;

  if (init && cur && init.D !== cur.D) {
    const keys = {}; for (const k in init.byKey) keys[k] = 1; for (const k in cur.byKey) keys[k] = 1;
    for (const k in keys) {
      const a = cur.byKey[k], b = init.byKey[k]; const base = a || b;
      const cq = a ? a.qty : 0, iq = b ? b.qty : 0; const common = Math.min(cq, iq);
      if (common > 0) { pushPair(base, "In Transit", init.D, "In Transit", cur.D, common);
        bumpTransit(base.material_id, base.batch_id, init.D, -common, base);
        bumpTransit(base.material_id, base.batch_id, cur.D, +common, base); }
      if (cq > iq) { pushPair(base, base.category, base.source, "In Transit", cur.D, cq - iq);
        bumpTransit(base.material_id, base.batch_id, cur.D, +(cq - iq), base); }
      else if (iq > cq) { pushPair(base, "In Transit", init.D, base.category, base.source, iq - cq);
        bumpTransit(base.material_id, base.batch_id, init.D, -(iq - cq), base); }
    }
    continue;
  }

  const D = (cur || init).D;
  const keys = {};
  if (init) for (const k in init.byKey) keys[k] = 1;
  if (cur) for (const k in cur.byKey) keys[k] = 1;
  for (const k in keys) {
    const a = cur ? cur.byKey[k] : null, b = init ? init.byKey[k] : null; const base = a || b;
    const cq = a ? a.qty : 0, iq = b ? b.qty : 0; const d = roundQty(cq - iq);
    if (d > 0) { pushPair(base, base.category, base.source, "In Transit", D, d); bumpTransit(base.material_id, base.batch_id, D, +d, base); }
    else if (d < 0) { pushPair(base, "In Transit", D, base.category, base.source, -d); bumpTransit(base.material_id, base.batch_id, D, d, base); }
  }
}

const rows = openRows.filter((r) => r.status === "In Transit");
const byKey = new Map();
for (const r of rows) { const k = `${r.material_id}|${r.batch_id || ""}|${r.transit_bin}`; if (!byKey.has(k)) byKey.set(k, []); byKey.get(k).push(r); }
for (const [, l] of byKey) l.sort((a, b) => { const da = String(a.transit_date || ""), db = String(b.transit_date || ""); if (da !== db) return da < db ? -1 : 1; return (a.line_no || 0) - (b.line_no || 0); });

const transitUpdates = [], transitCreates = [], shortages = [];
for (const [k, info] of transitDelta) {
  const delta = info.delta, material = info.material, batch = info.batch, bin = info.bin, meta = info.meta;
  if (delta === 0) continue;
  const list = byKey.get(k) || [];
  if (delta > 0) {
    if (list.length > 0) { const r = list[0]; const nq = roundQty(r.open_qty + delta);
      transitUpdates.push({ id: r.id, transit_qty: qtyStr(nq), open_qty: qtyStr(nq), status: "In Transit", received_date: null }); r.open_qty = nq; }
    else transitCreates.push({ doc_type: "Location Transfer", doc_id: ctx.docId, doc_no: ctx.docNo, doc_line_id: "", line_no: 0,
      parent_id: "", parent_no: "", parent_line_id: "", material_id: material, item_code: "", item_name: "", item_desc: "",
      item_uom: meta.material_uom, batch_id: batch, handling_unit_id: meta.handling_unit_id, plant_id: ctx.plantId,
      organization_id: ctx.orgId, transit_bin: bin, from_plant_id: ctx.plantId, from_bin: null, from_category: null,
      to_plant_id: ctx.plantId, to_bin: bin, to_category: "Unrestricted", transit_qty: qtyStr(delta), received_qty: qtyStr(0),
      open_qty: qtyStr(delta), status: "In Transit", transit_date: ctx.docDate, received_date: null, remark: "",
      target_doc_type: "Location Transfer", target_doc_id: ctx.docId, target_doc_no: ctx.docNo, target_doc_line_id: "", source_transit_id: "" });
  } else {
    let need = -delta;
    for (const r of list) { if (need <= 0) break; if (r.open_qty <= 0) continue; const take = roundQty(Math.min(r.open_qty, need)); const nq = roundQty(r.open_qty - take);
      transitUpdates.push({ id: r.id, transit_qty: qtyStr(nq), open_qty: qtyStr(nq), status: nq <= 0 ? "Cancelled" : "In Transit", received_date: null }); r.open_qty = nq; need = roundQty(need - take); }
    if (need > 0) shortages.push({ material_id: material, batch_id: batch, bin, shortage: qtyStr(need) });
  }
}

return {
  isDifferent: movements.length > 0 ? 1 : 0,
  movements, movementsLength: movements.length,
  transitCreates, hasTransitCreates: transitCreates.length > 0 ? 1 : 0,
  transitUpdates, hasTransitUpdates: transitUpdates.length > 0 ? 1 : 0,
  shortages, hasShortage: shortages.length > 0 ? 1 : 0,
  materialIds: Object.keys(materialSet),
  plant_id: ctx.plantId, organization_id: ctx.orgId, stock_movement_no: ctx.docNo, doc_date: ctx.docDate,
};

const movements = {{node:code_node_uht83Wzh.data.movements}} || [];
const idxRaw = {{node:get_cache_node_LOTreconIdx.data}};
const index = idxRaw ? parseInt(idxRaw, 10) : 0;
const m = movements[index] || {};
const itemsRaw = {{node:search_node_LOTitItemsRecon.data.data}} || [];
const items = Array.isArray(itemsRaw) ? itemsRaw : [itemsRaw];
const itemData = items.find((i) => i && String(i.id) === String(m.material_id)) || null;
return {
  material_id: m.material_id, batch_id: m.batch_id || null, quantity: m.quantity,
  material_uom: m.material_uom, subtractCategory: m.subtractCategory, subtractLocation: m.subtractLocation,
  addCategory: m.addCategory, addLocation: m.addLocation, handling_unit_id: m.handling_unit_id || null,
  manufacturing_date: m.manufacturing_date || null, expired_date: m.expired_date || null,
  itemData: itemData, index: index, nextIndex: index + 1,
};

const roundQty = (v) => parseFloat(parseFloat(v || 0).toFixed(3));
const qtyStr = (v) => Math.max(0, roundQty(v)).toFixed(3);

const page_status = {{workflowparams:pageStatus}};
const status = {{node:code_node_yPlLXIZW.data.stock_movement_status}};
const saveAs = {{workflowparams:saveAs}};

let allData;
if (page_status === "Add") {
  const rd = {{node:add_node_xxQX3uMU.data}};
  allData = Array.isArray(rd) ? rd[0] : rd;
} else if (page_status === "Edit" && status === "Draft") {
  allData = {{node:get_node_lvTzXllZ.data.data}};
} else {
  allData = {{node:code_node_yPlLXIZW.data.allData}};
}

const openRaw = {{node:search_node_LOTitOpenMain.data.data}};
const openRows = Array.isArray(openRaw) ? openRaw : (openRaw ? [openRaw] : []);

const lines = allData.stock_movement || [];
const plantId = allData.issuing_operation_faci;
const orgId = allData.organization_id;
const docId = allData.id || "";
const docNo = allData.stock_movement_no || "";
const docDate = allData.issue_date;

// STAGE = Draft->In Progress; COMPLETE = In Progress->Completed; DIRECT = Draft->Completed
const phase =
  saveAs === "In Progress" && status === "Draft" ? "STAGE"
    : saveAs === "Completed" && status === "In Progress" ? "COMPLETE"
      : "DIRECT";

const movements = [];
const transitCreates = [];
const materialSet = {};

for (const line of lines) {
  const D = line.location_id;
  let entries = [];
  try { entries = JSON.parse(line.temp_qty_data || "[]"); } catch (e) { entries = []; }
  if (!Array.isArray(entries)) entries = [];
  for (const e of entries) {
    const qty = roundQty(e.sm_quantity);
    if (qty <= 0) continue;
    const S = e.location_id;
    const C = e.category || "Unrestricted";
    const mat = e.material_id || line.item_selection;
    const batchId = e.batch_id || null;
    const hu = e.handling_unit_id || null;
    materialSet[mat] = true;
    const base = {
      material_id: mat, batch_id: batchId, quantity: qty,
      material_uom: e.material_uom || line.quantity_uom, handling_unit_id: hu,
      manufacturing_date: e.manufacturing_date || null, expired_date: e.expired_date || null,
    };
    if (phase === "STAGE") {
      // -C@S, +InTransit@D (relocated to destination)
      movements.push({ ...base, subtractCategory: C, subtractLocation: S, addCategory: "In Transit", addLocation: D });
      transitCreates.push({
        doc_type: "Location Transfer", doc_id: docId, doc_no: docNo, doc_line_id: line.id || "",
        line_no: line.line_index, parent_id: "", parent_no: "", parent_line_id: "",
        material_id: mat, item_code: "", item_name: "", item_desc: "",
        item_uom: base.material_uom, batch_id: batchId, handling_unit_id: hu,
        plant_id: plantId, organization_id: orgId, transit_bin: D,
        from_plant_id: plantId, from_bin: S, from_category: C,
        to_plant_id: plantId, to_bin: D, to_category: C,
        transit_qty: qtyStr(qty), received_qty: qtyStr(0), open_qty: qtyStr(qty),
        status: "In Transit", transit_date: docDate, received_date: null, remark: line.item_remark || "",
        target_doc_type: "Location Transfer", target_doc_id: docId, target_doc_no: docNo,
        target_doc_line_id: line.id || "", source_transit_id: "",
      });
    } else if (phase === "COMPLETE") {
      // -InTransit@D (relocated), +C@D
      movements.push({ ...base, subtractCategory: "In Transit", subtractLocation: D, addCategory: C, addLocation: D });
    } else {
      // DIRECT: -C@S, +C@D
      movements.push({ ...base, subtractCategory: C, subtractLocation: S, addCategory: C, addLocation: D });
    }
  }
}

// ledger close on COMPLETE: consume this doc's open rows FIFO with a guard.
const transitUpdates = [];
const shortages = [];
if (phase === "COMPLETE") {
  const key = (m, b, d) => `${m || ""}|${b || ""}|${d || ""}`;
  const pool = {};
  for (const r of openRows) {
    if (r.status !== "In Transit") continue;
    const k = key(r.material_id, r.batch_id, r.transit_bin);
    if (!pool[k]) pool[k] = [];
    pool[k].push({ row: r, remaining: roundQty(r.open_qty), consumed: 0 });
  }
  for (const k in pool) pool[k].sort((a, b) => {
    const da = String(a.row.transit_date || ""), db = String(b.row.transit_date || "");
    if (da !== db) return da < db ? -1 : 1;
    return (a.row.line_no || 0) - (b.row.line_no || 0);
  });
  for (const m of movements) {
    let need = roundQty(m.quantity);
    const bucket = pool[key(m.material_id, m.batch_id, m.addLocation)] || [];
    for (const ent of bucket) {
      if (need <= 0) break;
      if (ent.remaining <= 0) continue;
      const take = roundQty(Math.min(ent.remaining, need));
      ent.remaining = roundQty(ent.remaining - take);
      ent.consumed = roundQty(ent.consumed + take);
      need = roundQty(need - take);
    }
    if (need > 0) shortages.push({ material_id: m.material_id, batch_id: m.batch_id || "", bin: m.addLocation, shortage: qtyStr(need) });
  }
  for (const k in pool) for (const ent of pool[k]) {
    if (!ent.consumed) continue;
    const r = ent.row;
    transitUpdates.push({
      id: r.id,
      received_qty: qtyStr(roundQty((r.received_qty || 0) + ent.consumed)),
      open_qty: qtyStr(ent.remaining),
      status: ent.remaining <= 0 ? "Received" : "In Transit",
      received_date: ent.remaining <= 0 ? docDate : null,
    });
  }
}

return {
  phase, movements, movementsLength: movements.length,
  transitCreates, hasTransitCreates: transitCreates.length > 0 ? 1 : 0,
  transitUpdates, hasTransitUpdates: transitUpdates.length > 0 ? 1 : 0,
  shortages, hasShortage: shortages.length > 0 ? 1 : 0,
